// CHANCE_CARDS: each has an icon, a short label (shown while the reel spins),
// an apply(state) that mutates group scores, and a result(state) that returns
// the sentence shown on the reveal screen (after apply() already ran).
function clampScore(n) { return n; } // no floor — scores can go negative
function otherGroupIndex(state, offset) {
  const n = state.groups.length;
  return ((state.currentIndex + offset) % n + n) % n;
}
function lowestGroupIndex(state) {
  let best = 0;
  state.groups.forEach((g, i) => { if (g.score < state.groups[best].score) best = i; });
  return best;
}

const CHANCE_CARDS = [
  {
    icon: '🌟', label: 'Double Points',
    apply(state) { const g = state.groups[state.currentIndex]; g.score = clampScore(g.score * 2); },
    result(state) { return `${state.groups[state.currentIndex].name} doubles their score! 🌟`; }
  },
  {
    icon: '💰', label: 'Bonus +3',
    apply(state) { const g = state.groups[state.currentIndex]; g.score = clampScore(g.score + 3); },
    result(state) { return `${state.groups[state.currentIndex].name} gets a bonus of +3 points! 💰`; }
  },
  {
    icon: '💎', label: 'Big Bonus +5',
    apply(state) { const g = state.groups[state.currentIndex]; g.score = clampScore(g.score + 5); },
    result(state) { return `${state.groups[state.currentIndex].name} gets a BIG bonus of +5 points! 💎`; }
  },
  {
    icon: '😱', label: 'Lose 3 Points',
    apply(state) { const g = state.groups[state.currentIndex]; g.score = clampScore(g.score - 3); },
    result(state) { return `Oh no! ${state.groups[state.currentIndex].name} loses 3 points! 😱`; }
  },
  {
    icon: '🥷', label: 'Steal from Next Group',
    apply(state) {
      const from = otherGroupIndex(state, 1);
      const cur = state.groups[state.currentIndex];
      const other = state.groups[from];
      const amount = 3;
      other.score = clampScore(other.score - amount);
      cur.score = clampScore(cur.score + amount);
      this._from = from; this._amount = amount;
    },
    result(state) { return `${state.groups[state.currentIndex].name} steals ${this._amount} points from ${state.groups[this._from].name}! 🥷`; }
  },
  {
    icon: '🏴‍☠️', label: 'Steal from Previous Group',
    apply(state) {
      const from = otherGroupIndex(state, -1);
      const cur = state.groups[state.currentIndex];
      const other = state.groups[from];
      const amount = 3;
      other.score = clampScore(other.score - amount);
      cur.score = clampScore(cur.score + amount);
      this._from = from; this._amount = amount;
    },
    result(state) { return `${state.groups[state.currentIndex].name} steals ${this._amount} points from ${state.groups[this._from].name}! 🏴‍☠️`; }
  },
  {
    icon: '🔄', label: 'Swap with Next Group',
    apply(state) {
      const other = otherGroupIndex(state, 1);
      const cur = state.groups[state.currentIndex];
      const o = state.groups[other];
      [cur.score, o.score] = [o.score, cur.score];
      this._other = other;
    },
    result(state) { return `${state.groups[state.currentIndex].name} swaps scores with ${state.groups[this._other].name}! 🔄`; }
  },
  {
    icon: '🎁', label: 'Everyone Gains 2',
    apply(state) { state.groups.forEach(g => g.score = clampScore(g.score + 2)); },
    result() { return `Bonus round! Every group gains 2 points! 🎁`; }
  },
  {
    icon: '⚡', label: 'Others Lose 2',
    apply(state) {
      state.groups.forEach((g, i) => { if (i !== state.currentIndex) g.score = clampScore(g.score - 2); });
    },
    result(state) { return `${state.groups[state.currentIndex].name} is safe — every other group loses 2 points! ⚡`; }
  },
  {
    icon: '❄️', label: 'Freeze! Skip Next Turn',
    apply(state) { state.groups[state.currentIndex].frozen = true; },
    result(state) { return `${state.groups[state.currentIndex].name} is frozen and will skip their next turn! ❄️`; }
  },
  {
    icon: '🎯', label: 'Extra Turn',
    apply(state) { state.skipAdvanceOnce = true; },
    result(state) { return `${state.groups[state.currentIndex].name} gets an extra turn — go again! 🎯`; }
  },
  {
    icon: '🔀', label: 'Reverse Turn Order',
    apply(state) { state.direction *= -1; },
    result() { return `The turn order is reversed! 🔀`; }
  },
  {
    icon: '🎲', label: 'Mystery Points',
    apply(state) {
      const roll = 1 + Math.floor(Math.random() * 6);
      state.groups[state.currentIndex].score = clampScore(state.groups[state.currentIndex].score + roll);
      this._roll = roll;
    },
    result(state) { return `🎲 You rolled a ${this._roll}! ${state.groups[state.currentIndex].name} gets +${this._roll} points!`; }
  },
  {
    icon: '🤝', label: 'Help the Lowest Group',
    apply(state) {
      const idx = lowestGroupIndex(state);
      state.groups[idx].score = clampScore(state.groups[idx].score + 3);
      this._idx = idx;
    },
    result(state) { return `${state.groups[this._idx].name} (in last place) receives +3 points! 🤝`; }
  },
  {
    icon: '⚡', label: 'Speed Round',
    special: 'speedRound',
    apply() {},
    result() { return ''; }
  },
  {
    icon: '🔤', label: 'Quick Categories',
    special: 'quickCategories',
    apply() {},
    result() { return ''; }
  }
];

